def __init__(self, geometry: "Geometry", entity: _Entity):
    self._geometry = geometry
    self._entity = entity

def close(self):
    if self._owns_gmsh and gmsh.isInitialized():
        gmsh.finalize()
        self._owns_gmsh = False

